import { useMemo } from "react";
import { useConfig } from "../ConfigProvider";
import { toMerged } from "es-toolkit/object";

/**
 * Interpolates a template string with values.
 * Replaces {key} placeholders with corresponding values.
 *
 * @param template - Template string with {key} placeholders
 * @param values - Object with key-value pairs to substitute
 * @returns Interpolated string
 *
 * @example
 * ```ts
 * interpolate("Character {current} of {total}", { current: 1, total: 6 })
 * // Returns: "Character 1 of 6"
 * ```
 */
export function interpolate(
  template: string,
  values: Record<string, string | number>
): string {
  return template.replace(/\{(\w+)\}/g, (_, key: string) =>
    String(values[key] ?? "")
  );
}

// Recursive type for nested translation values
type TranslationValue = string | { [key: string]: TranslationValue };
type Translations = Record<string, Record<string, TranslationValue>>;

/**
 * Type utilities for inferring the merged translation shape from all locales.
 *
 * Given a translations object like:
 * { en: { a: { b: "str" } }, "en-US": { a: { c: "c-str" } } }
 *
 * The result type will be:
 * { a: { b: string; c: string } }
 */

// Get all keys from a union of objects
type KeysOfUnion<T> = T extends unknown ? keyof T : never;

// For a union of objects, extract the value type at key K (distributed over the union)
type ValueAtKey<T, K extends PropertyKey> =
  T extends Record<K, infer V> ? V : never;

// Recursively merge all objects in a union into a single object type
type DeepMergeUnion<T> = T extends string
  ? string
  : [T] extends [object]
    ? { [K in KeysOfUnion<T>]: DeepMergeUnion<ValueAtKey<T, K>> }
    : T;

// Extract all locale values from a translations object and deep-merge them
type MergedTranslations<T extends Translations> = DeepMergeUnion<T[keyof T]>;

/**
 * React hook for accessing translations with locale fallback support.
 *
 * Uses the locale from ConfigProvider (or falls back to browser locale/en-US).
 * When a specific locale (e.g., "en-GB") is provided, the hook will:
 * 1. Look for translations under the specific locale key ("en-GB")
 * 2. Fall back to the base locale ("en") if specific translations exist
 * 3. Deep merge them with specific translations taking precedence
 *
 * Supports nested JSON structures of any depth. Nested objects are merged deeply,
 * so keys from the base locale are preserved unless overridden by the specific locale.
 *
 * @param translations - Translation object with locale keys and their nested string objects
 * @returns Object containing all strings for the resolved locale (may be nested)
 *
 * @example
 * ```tsx
 * import translations from "./i18n.json";
 * import { useTranslations } from "@angi/one-design-system/components";
 *
 * function MyComponent() {
 *   const t = useTranslations(translations);
 *   return <span>{t.button.loading}</span>;
 * }
 * ```
 */
export function useTranslations<T extends Translations>(
  translations: T
): MergedTranslations<T> {
  const { locale } = useConfig();

  return useMemo(() => {
    // Extract base locale (e.g., "en" from "en-GB")
    const baseLocale = locale.includes("-")
      ? (locale.split("-")[0] as string)
      : locale;

    // Get base translations if they exist
    const baseTranslations = (translations[baseLocale] ?? {}) as Record<
      string,
      TranslationValue
    >;

    // Get specific translations if they exist (for locales with "-")
    const specificTranslations =
      locale.includes("-") && locale !== baseLocale
        ? ((translations[locale] ?? {}) as Record<string, TranslationValue>)
        : ({} as Record<string, TranslationValue>);

    // Deep merge: base first, then specific (specific overrides base, but nested objects are merged)
    // Cast is safe: MergedTranslations<T> represents the merged shape of all locales,
    // which is exactly what deepMerge produces at runtime
    return toMerged(
      baseTranslations,
      specificTranslations
    ) as MergedTranslations<T>;
  }, [translations, locale]);
}
